lib/tools-stats.ts： import { execSync } from 'child_process'; export function countLines(directory: string, extension: string): { total: number; files: { path: string; lines: number }[];
} { const cmd = `find ${directory} -name "*.${extension}" -not -path "*/node_modules/*" -not -path "*/.git/*"`; const files = execSync(cmd).toString().trim().split('\n'); const results = files.map(file => ({ path: file, lines: Number(execSync(`wc -l < ${file}`).toString().trim()) })); return { total: results.reduce((sum, r) => sum + r.lines, 0), files: results.sort((a, b) => b.lines - a.lines) };
}

